SELECT *
FROM training_rounds
WHERE status = 'completed' AND completion_time_seconds > 50;

SELECT COUNT(*) AS NumCompletedTrainingRounds
FROM training_rounds
WHERE status = 'completed' AND model_id = 1;

SELECT model_id, COUNT(*) AS TotalTrainingRounds
FROM training_rounds
GROUP BY model_id;

SELECT hyperparameters
FROM training_rounds
WHERE completion_time_seconds = (
    SELECT MIN(completion_time_seconds)
    FROM training_rounds
);

SELECT model_id, COUNT(round_id) AS num_training_rounds, COUNT(DISTINCT dataset_version) AS num_unique_datasets
FROM training_rounds
GROUP BY model_id;
